# tests/unit/test_scorers.py
import unittest
from evals.scorers import contains_refusal_phrase, valid_json_with_category

class FakeResponse:
    """Minimal stand-in for anthropic.types.Message — no import needed."""
    def __init__(self, text: str):
        self.content = [type("Block", (), {"text": text, "type": "text"})()]

class TestContainsRefusalPhrase(unittest.TestCase):

    def test_recognised_refusal_phrase_passes(self):
        r = FakeResponse("I'm not able to provide legal advice on this matter.")
        self.assertTrue(contains_refusal_phrase(r))

    def test_non_refusal_fails(self):
        r = FakeResponse("Here is a summary of your lease terms.")
        self.assertFalse(contains_refusal_phrase(r))

    def test_empty_response_fails(self):
        r = FakeResponse("")
        self.assertFalse(contains_refusal_phrase(r))

class TestValidJsonWithCategory(unittest.TestCase):

    def test_valid_billing_category_passes(self):
        r = FakeResponse('{"category": "billing", "confidence": 0.9}')
        self.assertTrue(valid_json_with_category(r))

    def test_invalid_json_fails(self):
        r = FakeResponse("not json")
        self.assertFalse(valid_json_with_category(r))

    def test_unknown_category_fails(self):
        r = FakeResponse('{"category": "unknown_value"}')
        self.assertFalse(valid_json_with_category(r))

if __name__ == "__main__":
    unittest.main()

# tests/doubles.py
"""
Reusable test doubles for the Anthropic client.
Import these in unit tests instead of writing MagicMock() inline.
"""
from dataclasses import dataclass, field
from typing import Any
import anthropic

@dataclass
class FakeContentBlock:
    text: str
    type: str = "text"

@dataclass
class FakeUsage:
    input_tokens:  int = 10
    output_tokens: int = 20

@dataclass
class FakeMessage:
    content: list = field(default_factory=list)
    usage:   FakeUsage = field(default_factory=FakeUsage)
    stop_reason: str = "end_turn"
    model:       str = "claude-haiku-4-5-20251001"

    @classmethod
    def with_text(cls, text: str, output_tokens: int = 20) -> "FakeMessage":
        return cls(
            content=[FakeContentBlock(text=text)],
            usage=FakeUsage(output_tokens=output_tokens),
        )

class FakeAnthropicMessages:
    """Mimics anthropic.Anthropic().messages with a fixed response sequence."""

    def __init__(self, responses: list[FakeMessage]):
        self._responses = list(responses)
        self._calls: list[dict] = []

    def create(self, **kwargs: Any) -> FakeMessage:
        self._calls.append(kwargs)
        if not self._responses:
            raise anthropic.InternalServerError(
                "No more responses", response=None, body={}
            )
        return self._responses.pop(0)

    @property
    def call_count(self) -> int:
        return len(self._calls)

    @property
    def last_call(self) -> dict:
        return self._calls[-1] if self._calls else {}

class FakeAnthropic:
    """Mimics anthropic.Anthropic() with a controllable messages interface."""

    def __init__(self, responses: list[FakeMessage]):
        self.messages = FakeAnthropicMessages(responses)
